<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">歐洲在肢體型加密貨幣勒索(扳手攻擊)案件中的佔比</text>
  <line x1="60" y1="340" x2="640" y2="340" stroke="#3f3f46" stroke-width="2"/>
  <rect x="180" y="213" width="120" height="127" fill="#3f3f46" rx="4"/>
  <text x="240" y="199" fill="#a1a1aa" font-size="20" font-weight="700" text-anchor="middle" font-family="sans-serif">22%</text>
  <text x="240" y="362" fill="#e4e4e7" font-size="13" text-anchor="middle" font-family="sans-serif">2024年</text>
